export function ngElDirective(): ng.Directive {
  return {
    restrict: "A",
    link(
      scope: ng.Scope,
      element: HTMLElement,
      attrs: import("../../core/compile/attributes.ts").Attributes,
    ): void {
      const attrMap = attrs as import("../../core/compile/attributes.ts").Attributes &
        Record<string, string>;
      const expr = attrMap.ngEl;

      const key = !expr ? element.id : expr;

      scope.$target[key] = element;
      const parent = element.parentNode;

      if (!parent) return;

      const observer = new MutationObserver((mutations) => {
        for (const mutation of mutations) {
          Array.from(mutation.removedNodes).forEach((removedNode: Node) => {
            if (removedNode === element) {
              delete scope.$target[key];
              observer.disconnect();
            }
          });
        }
      });

      observer.observe(parent, { childList: true });
    },
  };
}
