import {
  callBackOnce,
  hasOwn,
  hashKey,
  isArrayLike,
  isDefined,
  minErr,
  nullObject,
  values,
} from "../../shared/utils.js";
import { getBlockNodes, removeElement } from "../../shared/dom.ts";
import { $injectTokens } from "../../injection-tokens.ts";
import type { RepeatScope } from "./interface.ts";

const NG_REMOVED = "$$NG_REMOVED";

const ngRepeatMinErr = minErr("ngRepeat");

const VAR_OR_TUPLE_REGEX =
  /^(?:(\s*[$\w]+)|\(\s*([$\w]+)\s*,\s*([$\w]+)\s*\))$/;

type RepeatBlock = {
  id: string | number;
  scope?: RepeatScope;
  clone?: Node[];
};

type RepeatBlockMap = Record<string | number, RepeatBlock | true>;
type TrackByIdFn = (
  scope: ng.Scope,
  key: string | number,
  value: any,
) => string | number;

function removeBlockNodes(nodes: Node[]): void {
  nodes.forEach((node) => {
    if (node instanceof Element) {
      removeElement(node);
    } else if (node.parentNode) {
      node.parentNode.removeChild(node);
    }
  });
}

function insertNodesAfter(anchor: Node, nodes: Node[]): void {
  const parent = anchor.parentNode;

  if (!parent) {
    return;
  }

  let referenceNode = anchor.nextSibling;

  for (let i = 0; i < nodes.length; i++) {
    parent.insertBefore(nodes[i], referenceNode);
  }
}

ngRepeatDirective.$inject = [$injectTokens._animate];

export function ngRepeatDirective($animate: ng.AnimateService): ng.Directive {
  function updateScope(
    scope: RepeatScope & Record<string | number, any>,
    index: number,
    valueIdentifier: string | number,
    value: any,
    keyIdentifier: string | number | undefined,
    key: any,
    arrayLength: number,
  ): void {
    if (scope[valueIdentifier] !== value) {
      scope[valueIdentifier] = value;
    }

    if (keyIdentifier) {
      scope[keyIdentifier] = key;
    }

    if (value) {
      scope.$target._hashKey = value._hashKey;
    }

    scope.$index = index;
    scope.$first = index === 0;
    scope.$last = index === arrayLength - 1;
    scope.$middle = !(scope.$first || scope.$last);
    scope.$odd = !(scope.$even = (index & 1) === 0);
  }

  function getBlockStart(block: RepeatBlock): Node[] | undefined {
    return block.clone;
  }

  function getBlockEnd(block: RepeatBlock): Node | undefined {
    return block.clone?.[block.clone.length - 1];
  }

  function trackByIdArrayFn(
    _$scope: ng.Scope,
    _key: string | number,
    value: any,
  ): string | number {
    return hashKey(value);
  }

  function trackByIdObjFn(_$scope: ng.Scope, key: string | number): string | number {
    return key;
  }

  return {
    restrict: "A",
    transclude: "element",
    priority: 1000,
    terminal: true,
    compile(_$element: HTMLElement, $attr: ng.Attributes) {
      const expression = $attr.ngRepeat as string;
      const hasAnimate = !!$attr.animate;

      let match = expression.match(
        /^\s*([\s\S]+?)\s+in\s+([\s\S]+?)(?:\s+as\s+([\s\S]+?))?(?:\s+track\s+by\s+([\s\S]+?))?\s*$/,
      );

      if (!match) {
        throw ngRepeatMinErr(
          "iexp",
          "Expected expression in form of '_item_ in _collection_[ track by _id_]' but got '{0}'.",
          expression,
        );
      }

      const lhs = match[1];
      const rhs = match[2];
      const aliasAs = match[3];

      match = lhs.match(VAR_OR_TUPLE_REGEX);

      if (!match) {
        throw ngRepeatMinErr(
          "iidexp",
          "'_item_' in '_item_ in _collection_' should be an identifier or '(_key_, _value_)' expression, but got '{0}'.",
          lhs,
        );
      }

      const valueIdentifier = match[3] || match[1];
      const keyIdentifier = match[2];

      if (
        aliasAs &&
        (!/^[$a-zA-Z_][$a-zA-Z0-9_]*$/.test(aliasAs) ||
          /^(null|undefined|this|\$index|\$first|\$middle|\$last|\$even|\$odd|\$parent|\$root|\$id)$/.test(
            aliasAs,
          ))
      ) {
        throw ngRepeatMinErr(
          "badident",
          "alias '{0}' is invalid --- must be a valid JS identifier which is not a reserved name.",
          aliasAs,
        );
      }

      let trackByIdExpFn: TrackByIdFn | undefined;

      const swap = callBackOnce(() => {
        if (isDefined($attr.lazy) && isDefined($attr.swap)) {
          document
            .querySelectorAll($attr.swap as string)
            .forEach((node) => removeElement(node));
        }
      });

      function ngRepeatLink(
        $scope: ng.Scope & Record<string, any>,
        $element: ChildNode,
        attr: ng.Attributes,
        _ctrl: any,
        $transclude?: ng.TranscludeFn,
      ): void {
        let lastBlockMap: RepeatBlockMap = nullObject();

        $scope.$watch(
          rhs,
          (collection: any) => {
            swap();

            let index: number;
            let previousNode: Node = $element;
            let nextNode: Node | null | undefined;
            const nextBlockMap: RepeatBlockMap = nullObject();
            let key: string | number;
            let value: any;
            let trackById: string | number;
            let trackByIdFn: TrackByIdFn;
            let collectionKeys: any[];
            let block: RepeatBlock;
            let elementsToRemove: Node[] | undefined;

            if (aliasAs) {
              $scope[aliasAs] = collection;
            }

            if (isArrayLike(collection)) {
              collectionKeys = collection;
              trackByIdFn = trackByIdExpFn || trackByIdArrayFn;
            } else {
              trackByIdFn = trackByIdExpFn || trackByIdObjFn;
              collectionKeys = [];

              for (const itemKey in collection) {
                if (hasOwn(collection, itemKey) && itemKey.charAt(0) !== "$") {
                  (collectionKeys as string[]).push(itemKey);
                }
              }
            }

            const collectionLength = collectionKeys.length;
            const nextBlockOrder = new Array<RepeatBlock>(collectionLength);

            for (index = 0; index < collectionLength; index++) {
              key =
                collection === collectionKeys
                  ? index
                  : (collectionKeys[index] as string | number);
              value = collection[key];
              trackById = trackByIdFn($scope, key, value);

              if (lastBlockMap[trackById] && lastBlockMap[trackById] !== true) {
                block = lastBlockMap[trackById] as RepeatBlock;
                delete lastBlockMap[trackById];
                nextBlockMap[trackById] = block;
                nextBlockOrder[index] = block;
              } else if (nextBlockMap[trackById]) {
                values(nextBlockOrder).forEach((item) => {
                  if (item && item.scope) {
                    lastBlockMap[item.id] = item;
                  }
                });
                throw ngRepeatMinErr(
                  "dupes",
                  "Duplicates keys in a repeater are not allowed. Repeater: {0}, Duplicate key: {1} for value: {2}",
                  expression,
                  trackById,
                  value,
                );
              } else {
                nextBlockOrder[index] = {
                  id: trackById,
                  scope: undefined,
                  clone: undefined,
                };
                nextBlockMap[trackById] = true;
              }
            }

            for (const blockKey in lastBlockMap) {
              const staleBlock = lastBlockMap[blockKey];

              if (staleBlock === true) {
                continue;
              }

              block = staleBlock;
              elementsToRemove = block.clone;

              if (!elementsToRemove) {
                continue;
              }

              if (hasAnimate) {
                $animate.leave(elementsToRemove as any);
              } else {
                removeBlockNodes(elementsToRemove);
              }

              if (elementsToRemove[0]?.parentNode) {
                for (let i = 0, j = elementsToRemove.length; i < j; i++) {
                  (elementsToRemove[i] as any)[NG_REMOVED] = true;
                }
              }

              block.scope?.$destroy();
            }

            for (index = 0; index < collectionLength; index++) {
              key =
                collection === collectionKeys
                  ? index
                  : (collectionKeys[index] as string | number);
              value = collection[key];
              block = nextBlockOrder[index];

              if (block.scope) {
                nextNode = previousNode;

                do {
                  nextNode = nextNode.nextSibling;
                } while (nextNode && (nextNode as any)[NG_REMOVED]);

                if (getBlockStart(block)?.[0] !== nextNode) {
                  $animate.move(
                    getBlockNodes(block.clone as Node[]) as any,
                    null,
                    previousNode as any,
                  );
                }

                previousNode = getBlockEnd(block) || previousNode;
                updateScope(
                  block.scope as RepeatScope & Record<string | number, any>,
                  index,
                  valueIdentifier,
                  value,
                  keyIdentifier,
                  key,
                  collectionLength,
                );
              } else if ($transclude) {
                ($transclude as any)((clone: Node[], scope: RepeatScope) => {
                  block.scope = scope;
                  const endNode = clone[clone.length - 1];

                  if (hasAnimate) {
                    $animate.enter(clone as any, null, previousNode as any);
                  } else {
                    insertNodesAfter(previousNode, clone);
                  }

                  previousNode = endNode || previousNode;
                  block.clone = clone;
                  nextBlockMap[block.id] = block;
                  updateScope(
                    block.scope as RepeatScope & Record<string | number, any>,
                    index,
                    valueIdentifier,
                    value,
                    keyIdentifier,
                    key,
                    collectionLength,
                  );
                });
              }
            }

            lastBlockMap = nextBlockMap;
          },
          isDefined(attr.lazy),
        );
      }

      return ngRepeatLink;
    },
  };
}
